class Solution:
    def mergeTwoLists(self, l1, l2):
        dummy = ListNode()
        tail = dummy
        while l1 and l2:                # 两条都还有结点时,挑小的接上
            if l1.val <= l2.val:
                tail.next, l1 = l1, l1.next   # 接 l1 并把 l1 前移
            else:
                tail.next, l2 = l2, l2.next
            tail = tail.next
        tail.next = l1 or l2            # 把还剩的那条整体接上(另一条已空)
        return dummy.next
